SELECT SUM(cultural_events) AS total_cultural_events, SUM(cultural_funding) AS total_cultural_funding
FROM culture
WHERE year = 2020;

SELECT year, AVG(life_expectancy) AS average_life_expectancy
FROM healthcare
WHERE city_id = 0 AND year = 2020;

SELECT city_id, AVG(life_expectancy) AS average_life_expectancy
FROM healthcare
GROUP BY city_id;

SELECT cultural_events
FROM culture
WHERE city_id = 0 AND year = 2020;

SELECT city_id, SUM(population) AS total_population
FROM population_growth
GROUP BY city_id;
